import { describe, expect, it, vi } from 'vitest';

import { RegistryShim } from '../src/registry-shim';

/**
 * Tests for the Audit-2026-04-25 RegistryShim fixes.
 *
 * Bug 1: 5xx response from station -> body must be drained before retry.
 * Bug 2: terminal 5xx (post-retry) -> body must be drained before returning.
 * Bug 6: rejected `resolvePromise` must be cleared so subsequent callers retry.
 */

const RESOLVE_OK = {
  station: { station_endpoint: 'https://station.example.com' },
};

/**
 * Build a Response whose body stream tracks whether it was drained.
 * `cancel()` and full-read both flip `drained=true`. We use a getter on the
 * `drained` flag so each test can assert post-hoc that the runtime saw the
 * body consumed.
 */
function trackedResponse(
  body: string,
  init: ResponseInit,
): { res: Response; wasDrained: () => boolean } {
  let drained = false;
  // We use a ReadableStream so we can hook `pull` (which fires on full read)
  // and `cancel` (which fires on early-abort). Either path flips the flag.
  // This is more robust than monkey-patching `arrayBuffer`/`text` on the
  // Response, which TypeScript marks as read-only.
  const encoded = new TextEncoder().encode(body);
  const stream = new ReadableStream<Uint8Array>({
    pull(controller) {
      controller.enqueue(encoded);
      controller.close();
      drained = true;
    },
    cancel() {
      drained = true;
    },
  });
  const res = new Response(stream, init);
  return { res, wasDrained: () => drained };
}

describe('RegistryShim Bug 1 + Bug 2: 5xx body draining on retry path', () => {
  it('drains the first 5xx body before retrying, and the retry succeeds', async () => {
    const first = trackedResponse('upstream exploded', {
      status: 503,
      statusText: 'Service Unavailable',
    });
    const secondBody = 'ok-payload';
    const second = new Response(secondBody, { status: 200 });

    // Sequence of fetcher responses:
    //   1. resolve registry (200 + endpoint JSON)
    //   2. proxy fetch -> first attempt -> 503
    //   3. resolve registry again (cache invalidated after 5xx)
    //   4. proxy fetch -> retry -> 200
    const responses: Response[] = [
      new Response(JSON.stringify(RESOLVE_OK), { status: 200 }),
      first.res,
      new Response(JSON.stringify(RESOLVE_OK), { status: 200 }),
      second,
    ];
    const fetcher = {
      fetch: vi.fn(async (_req: Request | string, _init?: RequestInit) => {
        const r = responses.shift();
        if (!r) throw new Error('unexpected extra fetch');
        return r;
      }),
    };

    const shim = new RegistryShim({
      registryUrl: 'http://registry',
      knotId: 'k',
      startLayer: 0,
      endLayer: 1,
      fetcher,
    });

    const out = await shim.fetch(new Request('http://station/forward'));
    expect(out.status).toBe(200);
    expect(await out.text()).toBe(secondBody);

    // Bug 1 assertion: the failed 5xx body was drained before we issued the retry.
    expect(first.wasDrained()).toBe(true);

    // Sanity: we issued exactly two proxy attempts plus two registry resolves.
    expect(fetcher.fetch).toHaveBeenCalledTimes(4);
  });

  it('drains the terminal 5xx body when the retry also fails', async () => {
    const first = trackedResponse('boom', { status: 500 });
    const secondBody = 'still-broken';
    const second = trackedResponse(secondBody, { status: 502 });

    const responses: Response[] = [
      new Response(JSON.stringify(RESOLVE_OK), { status: 200 }),
      first.res,
      new Response(JSON.stringify(RESOLVE_OK), { status: 200 }),
      second.res,
    ];
    const fetcher = {
      fetch: vi.fn(async () => {
        const r = responses.shift();
        if (!r) throw new Error('unexpected extra fetch');
        return r;
      }),
    };

    const shim = new RegistryShim({
      registryUrl: 'http://registry',
      knotId: 'k',
      startLayer: 0,
      endLayer: 1,
      fetcher,
    });

    const out = await shim.fetch(new Request('http://station/forward'));
    // The terminal response surfaces the retry's status...
    expect(out.status).toBe(502);
    // ...with the body bytes preserved on the rebuilt Response.
    expect(await out.text()).toBe(secondBody);

    // Bug 1: first 5xx drained.
    expect(first.wasDrained()).toBe(true);
    // Bug 2: terminal 5xx drained on the original Response before rebuild.
    expect(second.wasDrained()).toBe(true);
  });
});

describe('RegistryShim Bug 6: rejected resolvePromise must not stick', () => {
  it('clears the cached resolve promise on rejection so the next call retries', async () => {
    // First /resolve fails (5xx) -> getEndpoint() rejects.
    // Second /resolve succeeds -> the proxy fetch should reach the station.
    const responses: Array<Response | Error> = [
      new Response('registry down', { status: 503 }),
      new Response(JSON.stringify(RESOLVE_OK), { status: 200 }),
      new Response('hello', { status: 200 }),
    ];
    const fetcher = {
      fetch: vi.fn(async () => {
        const r = responses.shift();
        if (!r) throw new Error('unexpected extra fetch');
        if (r instanceof Error) throw r;
        return r;
      }),
    };

    const shim = new RegistryShim({
      registryUrl: 'http://registry',
      knotId: 'k',
      startLayer: 0,
      endLayer: 1,
      fetcher,
    });

    // First call: registry returns 503 -> shim.fetch enters its catch branch
    // (network/registry failure surfaced as thrown Error from getEndpoint),
    // attempts one more retry inside the catch, which also tries to resolve
    // and... will consume the next entry. We want to assert that *after* a
    // hard rejection, the resolvePromise slot is cleared. So we use a setup
    // where the first attempt's resolve fails AND its retry-resolve also
    // fails, ensuring the whole shim.fetch() throws.
    //
    // Simpler: drive getEndpoint() directly via a public surface. The shim
    // does not expose getEndpoint(), but shim.fetch() exercises it. So we
    // arrange: 1st resolve 503, 2nd resolve 503 -> shim.fetch() throws.
    // Then on a *fresh* shim.fetch() call we feed 200 + 200 and it must
    // re-attempt resolve rather than re-await the cached rejection.
    //
    // Re-stage the queue accordingly:
    responses.length = 0;
    responses.push(
      new Response('registry down 1', { status: 503 }), // first resolve
      new Response('registry down 2', { status: 503 }), // catch-branch retry resolve
      new Response(JSON.stringify(RESOLVE_OK), { status: 200 }), // fresh resolve on 2nd shim.fetch()
      new Response('hello', { status: 200 }), // station proxy
    );

    await expect(
      shim.fetch(new Request('http://station/forward')),
    ).rejects.toThrow(/Failed to resolve/);

    // Bug 6 assertion: a subsequent call must perform a *fresh* resolve --
    // if the rejected promise had stuck, this call would re-throw the stale
    // 503 error without even consulting the fetcher. Instead, the shim hits
    // the queue again and pulls the 200 resolve + 200 proxy.
    const out = await shim.fetch(new Request('http://station/forward'));
    expect(out.status).toBe(200);
    expect(await out.text()).toBe('hello');

    // Confirm the queue was fully drained -- no responses left over, meaning
    // the second shim.fetch() actually issued the resolve + proxy pair.
    expect(responses.length).toBe(0);
  });
});
